	fmt.Fprintf(w, "    </div>\n")
	fmt.Fprintf(w, "</body>\n")
	fmt.Fprintf(w, "</html>\n")

	// Analytics tracking (mock implementation)
	trackSearchAnalytics(keyword)
}

// trackSearchAnalytics simulates analytics tracking for search keywords
func trackSearchAnalytics(keyword string) {
	// In a real implementation, this would send data to an analytics service
	// For now, we just log the search for demonstration purposes
	if keyword != "" {
		// Log the search event
		fmt.Printf("Search analytics: Search for '%s' was recorded\n", keyword)
	}
}

func main() {
	// Register the handler for product search
