// HandleProductSearch handles product search requests with keyword analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Write HTML response
	fmt.Fprintf(w, "<!DOCTYPE html>\n")
	fmt.Fprintf(w, "<html lang=\"en\">\n")
	fmt.Fprintf(w, "<head>\n")
	fmt.Fprintf(w, "    <meta charset=\"UTF-8\">\n")
	fmt.Fprintf(w, "    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n")
	fmt.Fprintf(w, "    <title>Search Results: %s</title>\n", escapedKeyword)
	fmt.Fprintf(w, "</head>\n")
	fmt.Fprintf(w, "<body>\n")
	fmt.Fprintf(w, "    <h2>Search Results: %s</h2>\n", escapedKeyword)
	fmt.Fprintf(w, "    <div class=\"search-results\">\n")
	fmt.Fprintf(w, "        <!-- Product search results would be displayed here -->\n")
	fmt.Fprintf(w, "        <p>Your search for '%s' returned results</p>\n", escapedKeyword)
	fmt.Fprintf(w, "    </div>\n")
	fmt.Fprintf(w, "</body>\n")
	fmt.Fprintf(w, "</html>\n")

	// Analytics tracking (mock implementation)
	trackSearchAnalytics(keyword)
}

// trackSearchAnalytics simulates analytics tracking for search keywords
func trackSearchAnalytics(keyword string) {
	// In a real implementation, this would send data to an analytics service
	// For now, we just log the search for demonstration purposes
	if keyword != "" {
		// Log the search event
		fmt.Printf("Search analytics: Search for '%s' was recorded\n", keyword)
	}
}

func main() {
	// Register the handler for product search
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Starting server on :8080")
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

