	fmt.Fprintf(w, "    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n")
	fmt.Fprintf(w, "    <title>Search Results: %s</title>\n", escapedKeyword)
	fmt.Fprintf(w, "</head>\n")
